  1	import { type FC, type ReactNode, useState } from 'react';
  2	import { AlertMessageForModals } from 'src/modules/Providers/modals/components/AlertMessageForModals';
  3	import { useForkliftTranslation } from 'src/utils/i18n';
  4	
  5	import type { IoK8sApiCoreV1Secret, V1beta1Provider } from '@kubev2v/types';
  6	import {
  7	  Button,
  8	  ButtonVariant,
  9	  Divider,
 10	  Flex,
 11	  FlexItem,
 12	  HelperText,
 13	  HelperTextItem,
 14	} from '@patternfly/react-core';
 15	import { type ValidationMsg, ValidationState } from '@utils/validation/Validation';
 16	
 17	import { getCredentialsEditModeByType } from './utils/getCredentialsEditModeByType';
 18	import { getCredentialsValidatorByType } from './utils/getCredentialsValidatorByType';
 19	import { isSecretDataChanged } from './utils/isSecretDataChanged';
 20	import { patchSecretData } from './utils/patchSecretData';
 21	
 22	import './CredentialsSectionEditViewModes.style.scss';
 23	
 24	type CredentialsSectionEditModeProps = {
 25	  provider: V1beta1Provider;
 26	  secret: IoK8sApiCoreV1Secret;
 27	  toggleEdit: () => void;
 28	};
 29	
 30	const CredentialsSectionEditMode: FC<CredentialsSectionEditModeProps> = ({
 31	  provider,
 32	  secret,
 33	  toggleEdit,
 34	}) => {
 35	  const { t } = useForkliftTranslation();
 36	  const [isLoading, setIsLoading] = useState(false);
 37	  const [dataChanged, setDataChanged] = useState(false);
 38	  const [changedSecret, setChangedSecret] = useState<IoK8sApiCoreV1Secret>(secret);
 39	  const [dataError, setDataError] = useState<ValidationMsg>({ type: ValidationState.Default });
 40	  const [alertMessage, setAlertMessage] = useState<ReactNode>();
 41	
 42	  const validator = getCredentialsValidatorByType(provider);
 43	  const CredentialsEditModeByType = getCredentialsEditModeByType(provider);
 44	
 45	  if (!secret?.data || !CredentialsEditModeByType || !validator) {
 46	    return <span className="text-muted">{t('No credentials found.')}</span>;
 47	  }
 48	  const setNewSecret = (newValue: IoK8sApiCoreV1Secret) => {
 49	    setChangedSecret(newValue);
 50	    setDataChanged(isSecretDataChanged(secret, newValue));
 51	    setDataError(validator(newValue, provider));
 52	    setAlertMessage(null);
 53	  };
 54	
 55	  const onCancel = () => {
 56	    setNewSecret(secret);
 57	    toggleEdit();
 58	  };
 59	
 60	  const onNewSecretChange = (newValue: IoK8sApiCoreV1Secret) => {
 61	    setNewSecret(newValue);
 62	  };
 63	
 64	  const onUpdate = async () => {
 65	    setIsLoading(true);
 66	
 67	    try {
 68	      await patchSecretData(changedSecret, true);
 69	      setDataChanged(false);
 70	
 71	      setIsLoading(false);
 72	      toggleEdit();
 73	    } catch (err: unknown) {
 74	      const errorMessage = err instanceof Error ? err.message : err?.toString();
 75	      setAlertMessage(errorMessage);
 76	      setIsLoading(false);
 77	    }
 78	  };
 79	
 80	  return (
 81	    <>
 82	      <Flex>
 83	        <FlexItem>
 84	          <Button
 85	            variant={ButtonVariant.primary}
 86	            onClick={onUpdate}
 87	            isDisabled={!dataChanged || dataError.type === ValidationState.Error}
 88	            isLoading={isLoading}
 89	          >
 90	            {t('Update credentials')}
 91	          </Button>
 92	        </FlexItem>
 93	        <FlexItem>
 94	          <Button variant={ButtonVariant.secondary} onClick={onCancel}>
 95	            {t('Cancel')}
 96	          </Button>
 97	        </FlexItem>
 98	      </Flex>
 99	
100	      <HelperText className="forklift-section-secret-edit">
101	        {dataError.type === ValidationState.Error ? (
102	          <HelperTextItem variant="error">{dataError.msg}</HelperTextItem>
103	        ) : (
104	          <HelperTextItem variant="indeterminate">
105	            {t(
106	              'Click the update credentials button to save your changes, button is disabled until a change is detected.',
107	            )}
108	          </HelperTextItem>
109	        )}
110	      </HelperText>
111	
112	      <Divider />
113	
114	      {alertMessage && <AlertMessageForModals title={t('Error')} message={alertMessage} />}
115	
116	      <CredentialsEditModeByType secret={changedSecret} onNewSecretChange={onNewSecretChange} />
117	    </>
118	  );
119	};
120	
121	export default CredentialsSectionEditMode;

